function brl(v) {
  const parts = parseFloat(v).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}

function num(v) {
  const parts = parseFloat(v).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return parts[0] + ',' + parts[1];
}

function num8(v) {
  const parts = parseFloat(v).toFixed(8).split('.');
